import sys

class Student:
    def __init__(self, nume, nota):
        self.nume = nume
        self.nota = nota

    def este_admis(self):
        return self.nota >= 5.0

def main():
    lines = sys.stdin.read().split()
    if len(lines) < 2: return
    nume = lines[0]
    nota = float(lines[1])
    s = Student(nume, nota)
    if s.este_admis():
        print("ADMIS")
    else:
        print("RESPINS")

if __name__ == '__main__':
    main()

import sys

def is_balanced(expr):
    stack = []
    for char in expr:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack: return False
            stack.pop()
    return len(stack) == 0

def main():
    lines = sys.stdin.read().split()
    if not lines: return
    expr = lines[0]
    if is_balanced(expr):
        print("CORECT")
    else:
        print("INCORECT")

if __name__ == '__main__':
    main()

import sys

def binary_search(arr, target):
    low, high = 0, len(arr) - 1
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def main():
    lines = sys.stdin.read().split()
    if len(lines) < 2: return
    target = int(lines[0])
    arr = [int(i) for i in lines[1:]]
    print(binary_search(arr, target))

if __name__ == '__main__':
    main()
